class Solution {
public:
    int minStarting"
        int n = s.size(), m = pattern.size();
        if (m > n) return -1;
        vector<int> z(n);
        string combined = pattern + "#" + s;
        int len = combined.size();
        vector<int> z_all(len);
        int l = 0, r = 0;
        for (int i = 1; i < len; ++i) {
            if (i <= r) z_all[i] = min(r - i + 1, z_all[i - l]);
            while (i + z_all[i] < len && combined[z_all[i]] == combined[i + z_all[i]]) ++z_all[i];
            if (i + z_all[i] - 1 > r) {
                l = i;
                r = i + z_all[i] - 1;
            }
        }
        for (int i = 0; i < n; ++i) z[i] = z_all[i + m + 1];
        combined = string(pattern.rbegin(), pattern.rend()) + "#" + string(s.rbegin(), s.rend());
        len = combined.size();
        vector<int> z_rev_all(len);
        l = 0, r =  0;
        for (int i = 1; i < len; ++i) {
            if (i <= r) z_rev_all[i] = min(r - i + 1, z_rev_all[i - l]);
            while (i + z_rev_all[i] < len && combined[z_rev_all[i]] == combined[i + z_rev_all[i]]) ++z_rev_all[i];
            if (i + z_rev_all[i] - 1 > r) {
                l = i;
                r = i + z_rev_all[i] - 1;
            }
        }
        vector<int> z_rev(n);
        for (int i = 0; i < n; ++i) z_rev[i] = z_rev_all[i + m + 1];
        for (int i = 0; i <= n - m; ++i) {
            int pref = z[i];
            int suf = z_rev[n - (i + m)];
            if (pref + suf >= m - 1) return i;
        }
        return -1;
    }
};
